using Microsoft.EntityFrameworkCore;
namespace Acutis.Community.Api;
public sealed class CommunityDbContext(DbContextOptions<CommunityDbContext> options):DbContext(options){public DbSet<CommunityTenant> Tenants=>Set<CommunityTenant>();public DbSet<CommunityMembership> Memberships=>Set<CommunityMembership>();public DbSet<CommunityParticipant> Participants=>Set<CommunityParticipant>();public DbSet<CommunityAppointment> Appointments=>Set<CommunityAppointment>();public DbSet<CommunityAssessment> Assessments=>Set<CommunityAssessment>();public DbSet<CommunityCarePlan> CarePlans=>Set<CommunityCarePlan>();public DbSet<CommunityFormDefinition> FormDefinitions=>Set<CommunityFormDefinition>();public DbSet<CommunityFormAssignment> FormAssignments=>Set<CommunityFormAssignment>();public DbSet<CommunityFormResponse> FormResponses=>Set<CommunityFormResponse>();public DbSet<CommunityAuditEvent> AuditEvents=>Set<CommunityAuditEvent>();protected override void OnModelCreating(ModelBuilder b){b.Entity<CommunityMembership>().HasIndex(x=>new{x.TenantId,x.ExternalSubject}).IsUnique();b.Entity<CommunityMembership>().HasOne(x=>x.Tenant).WithMany().HasForeignKey(x=>x.TenantId);b.Entity<CommunityAppointment>().HasOne(x=>x.Participant).WithMany().HasForeignKey(x=>x.ParticipantId).OnDelete(DeleteBehavior.SetNull);b.Entity<CommunityAssessment>().HasOne<CommunityParticipant>().WithMany().HasForeignKey(x=>x.ParticipantId);b.Entity<CommunityCarePlan>().HasOne<CommunityParticipant>().WithMany().HasForeignKey(x=>x.ParticipantId);b.Entity<CommunityFormDefinition>().HasIndex(x=>new{x.TenantId,x.Code,x.Version}).IsUnique();b.Entity<CommunityFormAssignment>().HasOne<CommunityFormDefinition>().WithMany().HasForeignKey(x=>x.FormDefinitionId);b.Entity<CommunityFormAssignment>().HasOne<CommunityParticipant>().WithMany().HasForeignKey(x=>x.ParticipantId);b.Entity<CommunityFormResponse>().HasOne<CommunityFormAssignment>().WithMany().HasForeignKey(x=>x.AssignmentId);}}
